export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

const SERVER_CONTENT_PATTERNS = [
  /createServer/,
  /\.listen\s*\(/,
  /http\.createServer/,
  /https\.createServer/,
  /import\s+.*?['"]http['"]/,
  /require\s*\(\s*['"]http['"]\s*\)/,
];

const TUTORIAL_RX = /\b(learn|tutorial|example\s+repo|starter\s+kit|boilerplate|workshop|playground|cheatsheet)\b/i;

const LIBRARY_KEYWORDS = new Set([
  'library', 'plugin', 'sdk', 'toolkit', 'cli', 'build-tool', 'bundler',
  'compiler', 'tool', 'utilities', 'utils', 'helper', 'middleware'
]);

function isApiRouteFile(p) {
  if (!/\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  return /(^|\/)api\//.test(p) ||
         /(^|\/)pages\/api\//.test(p) ||
         /(^|\/)app\/api\//.test(p) ||
         /(^|\/)src\/pages\/api\//.test(p) ||
         /(^|\/)src\/app\/api\//.test(p) ||
         /(^|\/)server\/api\//.test(p) ||
         /(^|\/)functions\//.test(p) ||
         /(^|\/)controllers\//.test(p) ||
         /(^|\/)routes\/api\//.test(p) ||
         /\+server\.(ts|js|mjs|cjs)$/.test(p) ||
         /\+page\.server\.(ts|js|mjs|cjs)$/.test(p);
}

function isServerEntryFile(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  const b = p.slice(p.lastIndexOf('/') + 1);
  if (/^(server|listen|worker|main)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) return true;
  return /\/(server|listen|worker|main|app|index)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p);
}

function isRouteFile(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) return false;
  return /(^|\/)routes\/[^/]+\.(js|ts|mjs|cjs)$/.test(p);
}

function isConfigFile(p) {
  return /\.config\.(js|ts|mjs|cjs|mts|cts)$/.test(p) && !/(^|\/)node_modules\//.test(p);
}

function hasCorsDep(pj) {
  if (!pj) return false;
  const deps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}), ...(pj.peerDependencies || {}) };
  return Object.keys(deps).some(k => {
    const name = k.includes('/') ? k.split('/').pop() : k;
    return name.toLowerCase().includes('cors');
  });
}

function isTutorial(pj) {
  if (!pj) return false;
  const signals = [pj.name, pj.description, ...(pj.keywords || [])].filter(Boolean);
  return signals.some(s => TUTORIAL_RX.test(s));
}

function isLibraryOrTool(pj, tree) {
  if (!pj) return false;
  const scripts = pj.scripts || {};
  const hasStart = !!(scripts.start || scripts.serve || scripts['start:prod'] || scripts.preview);
  const isPrivate = pj.private === true;
  const hasWorkspaces = !!(pj.workspaces) || tree.some(p => /(^|\/)pnpm-workspace\.yaml$/.test(p));
  const hasPackagesDir = tree.some(p => /^(packages|pkgs)\/[^/]+\//.test(p));
  const hasAppsDir = tree.some(p => /^(apps|sites|services|clients|studio)\/[^/]+\//.test(p));
  const hasServerFile = tree.some(isServerEntryFile);
  const hasApi = tree.some(isApiRouteFile);

  if (isPrivate && hasWorkspaces && hasPackagesDir && !hasAppsDir && !hasStart && !hasServerFile && !hasApi) {
    return true;
  }

  const hasEntry = !!(pj.main || pj.module || pj.exports || pj.types || pj.typings);
  if (hasEntry && !isPrivate && !hasStart && !hasServerFile && !hasApi) {
    return true;
  }

  const keywords = (pj.keywords || []).map(k => k.toLowerCase());
  if (keywords.some(k => LIBRARY_KEYWORDS.has(k)) && !hasStart && !hasApi && !hasServerFile) {
    return true;
  }

  return false;
}

async function findMonorepoCorsDep(files, tree) {
  const pkgPaths = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p));
  for (const pkgPath of pkgPaths.slice(0, 100)) {
    if (pkgPath === 'package.json') continue;
    const content = await files.get(pkgPath);
    if (!content) continue;
    try {
      const sub = JSON.parse(content);
      if (hasCorsDep(sub)) return pkgPath;
    } catch {
      // ignore invalid JSON
    }
  }
  return null;
}

async function scanFilesForCors(files, tree) {
  const candidates = [];
  for (const p of tree) {
    if (!/\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p)) continue;
    if (/(^|\/)node_modules\//.test(p)) continue;
    if (/(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build)\//i.test(p)) continue;

    let score = 0;
    const b = p.slice(p.lastIndexOf('/') + 1);

    if (isConfigFile(p)) score += 100;
    if (isApiRouteFile(p)) score += 90;
    if (isServerEntryFile(p)) score += 80;
    if (/middleware\.(js|ts|mjs|cjs)$/.test(b)) score += 70;
    if (isRouteFile(p)) score += 60;
    if (/handler\.(js|ts|mjs|cjs)$/.test(b)) score += 50;
    if (/^src\//.test(p)) score += 10;

    if (score > 0) candidates.push({ path: p, score });
  }

  candidates.sort((a, b) => b.score - a.score);

  for (const { path } of candidates.slice(0, 100)) {
    const content = await files.get(path);
    if (!content) continue;
    for (const pat of CORS_PATTERNS) {
      if (pat.test(content)) return path;
    }
  }
  return null;
}

async function rootFileLooksLikeServer(files, tree) {
  const rootFiles = tree.filter(p => {
    if (p.includes('/')) return false;
    return /^(index|app|main|server)\.(js|ts|mjs|cjs)$/.test(p);
  });
  for (const p of rootFiles) {
    const content = await files.get(p);
    if (!content) continue;
    if (SERVER_CONTENT_PATTERNS.some(pat => pat.test(content))) return true;
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (!tree || tree.length === 0 || repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository', findings: [] };
    }

    if (isTutorial(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repository', findings: [] };
    }

    if (isLibraryOrTool(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or tool source code', findings: [] };
    }

    if (hasCorsDep(packageJson)) {
      return { checkId, status: 'pass', confidence: 'high', message: 'CORS dependency found in package.json', findings: [] };
    }

    const subCors = await findMonorepoCorsDep(files, tree);
    if (subCors) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${subCors}`, findings: [{ file: subCors, issue: 'CORS dependency detected' }] };
    }

    const corsFile = await scanFilesForCors(files, tree);
    if (corsFile) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${corsFile}`, findings: [{ file: corsFile, issue: 'CORS detected' }] };
    }

    const hasApi = tree.some(isApiRouteFile);
    const hasServerFile = tree.some(isServerEntryFile);
    const hasRoute = tree.some(isRouteFile);
    const rootIsServer = await rootFileLooksLikeServer(files, tree);

    if (hasApi || hasServerFile || hasRoute || rootIsServer) {
      return { checkId, status: 'fail', confidence: 'medium', message: 'Server-side code detected but no CORS configuration found', findings: [{ file: 'unknown', issue: 'Missing CORS configuration' }] };
    }

    return { checkId, status: 'not-applicable', confidence: 'high', message: 'No server-side or API code detected', findings: [] };
  } catch (err) {
    console.error(`[${checkId}] Unexpected error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error during CORS check: ${err.message}`, findings: [{ file: 'unknown', issue: `Error: ${err.message}` }] };
  }
}
